const cpf = ($input.first().json['CPF'] || '').toString().replace(/\D/g, '');
if (cpf.length !== 11) throw new Error('CPF inválido: informe 11 dígitos. Recebido: ' + cpf);

let escola = 70532; // Padrão
if ($('Formulário - CPF').first() && $('Formulário - CPF').first().json.query && $('Formulário - CPF').first().json.query.escola) {
    escola = $('Formulário - CPF').first().json.query.escola;
} else if ($('Formulário - CPF').first() && $('Formulário - CPF').first().json.body && $('Formulário - CPF').first().json.body.escola) {
    escola = $('Formulário - CPF').first().json.body.escola;
} else if ($input.first().json['escola']) {
    escola = $input.first().json['escola'];
}

return [{ json: { cpf, escola: escola.toString() } }];

const token = $input.item.json.accessToken || $input.item.json.token || $input.item.json.access_token || '';
let cpf = $('Validar CPF').first().json.cpf;
cpf = cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, "$1.$2.$3-$4");
let escola = $('Validar CPF').first().json.escola;

const codCli = escola == 8731 ? 8731 : 70532;
const apiKey = escola == 8731 ? '87E821' : '0EA64A';

return [{ json: { token, cpf, codCli, apiKey } }];

let alunos = $input.item.json;
if (!Array.isArray(alunos)) alunos = [alunos];

// Em vez de pegar apenas o primeiro aluno, pegamos TODOS que têm esse CPF
let items = [];
let token = $('Preparar Vars').first().json.token;

for (let a of alunos) {
    if (a && a.student_id) {
        items.push({
            json: {
                alunoId: a.student_id,
                token: token,
                nome: a.name
            }
        });
    }
}

// Se não achar nenhum, retorna vazio para parar o fluxo
return items;

let items = $input.all();
let boletos = [];

for (let item of items) {
    let payload = item.json;
    // Sponte V3 retorna { pagination: {...}, data: [ ... ] }
    let dataArray = payload.data || payload.Data || [];
    if (!Array.isArray(dataArray) && Array.isArray(payload)) dataArray = payload;

    for (let conta of dataArray) {
        if (conta.parcelas && Array.isArray(conta.parcelas)) {
            for (let p of conta.parcelas) {
                p.ContaReceberID = conta.contaReceberID || conta.ContaReceberID;
                boletos.push(p);
            }
        } else if (conta.Parcelas && Array.isArray(conta.Parcelas)) {
            for (let p of conta.Parcelas) {
                p.ContaReceberID = conta.contaReceberID || conta.ContaReceberID;
                boletos.push(p);
            }
        } else {
            boletos.push(conta);
        }
    }
}

let today = new Date();
let hasOver6Days = false;
let boletosParaEnviar = [];

for (let b of boletos) {
    let situacao = b.situacao || b.Situacao || 'SemStatus';
    let sUpper = String(situacao).toUpperCase();

    // Ignorar as que já estão pagas ou canceladas
    if (sUpper === 'PAGO' || sUpper === 'CANCELADA' || sUpper === 'CANCELADO' || sUpper === 'QUITADO' || sUpper === 'QUITADA' || sUpper === '2' || sUpper === '3') continue;

    let vencimentoStr = b.dataVencimento || b.DataVencimento;
    if (!vencimentoStr) continue;

    let vencimento = new Date(vencimentoStr);
    let diffTime = today - vencimento;
    let diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays >= 6) {
        hasOver6Days = true;
    } else {
        let boletoText = b.linhaDigitavel || b.LinhaDigitavel || b.LinhaDigitavelCopia;
        if (!boletoText) {
            let valor = b.valor || b.Valor || 0;
            let vFormat = vencimento.toLocaleDateString('pt-BR');
            let valFormat = parseFloat(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
            boletoText = `• Parcela ${b.numeroParcela || ''}: ${valFormat} - Venc: ${vFormat} (Status: ${situacao})`;
        }
        boletosParaEnviar.push(boletoText);
    }
}

let message = "VOCÊ ESTÁ EM DIA!";
if (hasOver6Days) {
    message = "entre em contato com: 0800 886 0663";
} else if (boletosParaEnviar.length > 0) {
    message = "Aqui estão suas faturas em aberto:\n\n" + boletosParaEnviar.join("\n\n");
}

return [{ json: { message } }];
